import React  from 'react'
import { useState } from 'react';
//import '../styles/Style.css';

function StudentInfo() {
    const [students, setStudents] = useState([]);

    const [studentID, setStudentID] = useState('');
    const [studentName, setStudentName] = useState('');
    const [studentMajor, setStudentMajor] = useState('');
    const [studentGpa, setStudentGpa] = useState('');

    const handleAddStudent = () => {
    if (studentID.trim() !== '' && studentName.trim() !== '' 
    && studentMajor.trim() !== '' && studentGpa.trim() !== '') { 
      students.push({
				studentID: studentID,
				studentName: studentName,
				studentMajor: studentMajor,
        studentGpa: studentGpa,			
			});
      setStudentID("");
			setStudentName("");
			setStudentMajor("");
      setStudentGpa("");

      setStudents([...students]); // Add the new item to the list
     
    }
  };

  // Function to handle removing an item
  const handleRemoveStudent = (id) => {
    setStudents(students.filter((student) => student.studentID !== id)); // Filter out the item to be removed
  };
  return (
<div> 
  <h1>Student List</h1>
  <div className = 'container'>
       <input
        type="number"
        value={studentID}
        onChange={(e) => setStudentID(e.target.value)}
        placeholder="Student ID "
      />
<br/>
      <input
        type="text"
        value={studentName}
        onChange={(e) => setStudentName(e.target.value)}
        placeholder="Student Name"
      />
      <br/>
      <input
        type="text"
        value={studentMajor}
        onChange={(e) => setStudentMajor(e.target.value)}
        placeholder="Student Major"
      />
      <br/>
        <input
        type="number"
        value={studentGpa}
        onChange={(e) => setStudentGpa(e.target.value)}
        placeholder="GPA"
      />
      <br/>
      <button onClick={handleAddStudent}>Add Student</button>
      <br/><br/>

      {/* Displaying the List of Items */}
	
				<table border='1' align="center">
					<thead>
						<tr>
							<th>Student ID</th>
							<th>Student Name </th>
							<th>Student Major </th>
              <th>GPA </th>
              <th>Action </th>
						</tr>
					</thead>
					<tbody>
           {students.map(student => (
              <tr key={student.id}>
                <td>{student.studentID}</td> 
                <td>{student.studentName}</td>
                <td>{student.studentMajor}</td>
                <td>{student.studentGpa}</td>
                <td>
                  <button onClick={() => handleRemoveStudent(student.studentID)}>Delete</button>
                </td>
              </tr>
            ))} 
</tbody>
</table>
</div>   
    </div>
 
  )
}
export default StudentInfo
